mapper.select:
select status
    from tb_order
where out_trade_no = #{outTradeNo} and customer_id = #{customerId}

select count(*) from tb_order where customer_id = #{customerId}

        and (
            goods_title like concat('%', #{keyword}, '%') or
            goods_description like concat('%', #{keyword}, '%') or
            out_trade_no like concat('%', #{keyword}, '%')
        )


        and status = #{status}

SELECT o.id, o.goods_id, o.snapshot_id, o.goods_title, o.goods_description, o.goods_image, o.out_trade_no, o.number, o.goods_price, o.payable_amount, o.status, o.create_time, COALESCE(a.appoint_count, 0) AS appoint_count FROM tb_order o LEFT JOIN ( SELECT a.order_id, COUNT(*) AS appoint_count FROM tb_appointment a INNER JOIN tb_order o2 ON a.order_id = o2.id WHERE o2.customer_id = #{customerId} GROUP BY a.order_id ) a ON a.order_id = o.id WHERE o.customer_id = #{customerId}
AND o.status = #{status}
AND ( o.goods_title LIKE CONCAT('%', #{keyword}, '%') OR o.out_trade_no LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY o.create_time DESC LIMIT #{start}, #{length}

