mapper.select:
SELECT o.id, o.goods_title AS goodsTitle, o.goods_price AS goodsPrice, o.snapshot_id AS snapshotId, o.number, o.total_amount AS totalAmount, c.photo, c.name, c.sex, c.tel, c.create_time AS registerTime, o.status, o.out_trade_no AS outTradeNo, o.transaction_id AS transactionId, o.out_refund_no AS outRefundNo, o.create_date AS createDate, o.create_time AS createTime, o.refund_date AS refundDate, o.refund_time AS refundTime, COALESCE(a.appointment_count, 0) AS num FROM tb_order o INNER JOIN tb_customer c ON o.customer_id = c.id INNER JOIN tb_goods g ON o.goods_id = g.id LEFT JOIN ( SELECT order_id, COUNT(*) as appointment_count FROM tb_appointment GROUP BY order_id ) a ON o.id = a.order_id
AND c.tel = #{pageRequest.tel}
AND g.code = #{pageRequest.code}
AND o.out_trade_no = #{pageRequest.outTradeNo}
AND o.status = #{pageRequest.status}
AND o.create_date BETWEEN #{pageRequest.startDate} AND #{pageRequest.endDate}
AND o.goods_title LIKE CONCAT('%', #{pageRequest.keyword}, '%')
AND c.id = #{pageRequest.customerId}
ORDER BY o.id DESC LIMIT #{start}, #{pageRequest.length}

SELECT COUNT(DISTINCT o.id)
    FROM tb_order o
INNER JOIN tb_customer c ON o.customer_id = c.id
INNER JOIN tb_goods g ON o.goods_id = g.id


        AND c.tel = #{tel}


        AND g.code = #{code}


        AND o.out_trade_no = #{outTradeNo}


        AND o.status = #{status}


        AND o.create_date BETWEEN #{startDate} AND #{endDate}


        AND o.goods_title LIKE CONCAT('%', #{keyword}, '%')


        AND c.id = #{customerId}
